import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, Plus } from 'lucide-react';

const Schedule = () => {
  const [currentDate, setCurrentDate] = useState(new Date());

  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const currentDay = currentDate.getDay();
  const currentDayNumber = currentDate.getDate();

  // Sample schedule data
  const scheduleData = {
    Monday: [
      { time: '06:00 AM', title: 'Morning Run', type: 'Cardio', duration: 45 },
      { time: '06:00 PM', title: 'Upper Body', type: 'Strength', duration: 60 },
    ],
    Tuesday: [
      { time: '06:00 PM', title: 'HIIT', type: 'HIIT', duration: 45 },
    ],
    Wednesday: [
      { time: '06:00 AM', title: 'Yoga', type: 'Yoga', duration: 60 },
    ],
    Thursday: [
      { time: '06:00 PM', title: 'Lower Body', type: 'Strength', duration: 60 },
    ],
    Friday: [
      { time: '06:00 PM', title: 'Cardio', type: 'Cardio', duration: 45 },
    ],
    Saturday: [
      { time: '08:00 AM', title: 'CrossFit', type: 'CrossFit', duration: 90 },
    ],
  };

  const todaySchedule = scheduleData[days[currentDay]] || [];

  return (
    <div className="schedule">
      <h1 className="page-title">Weekly Schedule</h1>

      <div className="schedule-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <div>
          <h2 style={{ fontSize: '1.3rem' }}>{days[currentDay]} - {currentDayNumber}</h2>
          <p style={{ color: 'var(--text-secondary)' }}>Today</p>
        </div>
        <div style={{ display: 'flex', gap: '12px' }}>
          <button className="icon-btn" onClick={() => setCurrentDate(new Date(currentDate.setDate(currentDate.getDate() - 7)))}>
            <ChevronLeft size={20} />
          </button>
          <button className="icon-btn" onClick={() => setCurrentDate(new Date(currentDate.setDate(currentDate.getDate() + 7)))}>
            <ChevronRight size={20} />
          </button>
          <button className="btn-primary" style={{ width: 'auto', marginTop: 0 }}>
            <Plus size={18} style={{ marginRight: '6px' }} />
            Add Workout
          </button>
        </div>
      </div>

      {/* Week View */}
      <div className="schedule-grid">
        {days.map((day, index) => {
          const daySchedule = scheduleData[day] || [];
          const isToday = index === currentDay;
          
          return (
            <div className="day-column" key={day}>
              <div className="day-header" style={{ background: isToday ? 'var(--primary)' : 'var(--bg-input)' }}>
                <span className="day-name">{day}</span>
              </div>
              <div className="day-events">
                {daySchedule.length === 0 ? (
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem', textAlign: 'center', marginTop: '20px' }}>
                    Rest Day
                  </p>
                ) : (
                  daySchedule.map((event, idx) => (
                    <div 
                      className="event-item" 
                      key={idx}
                      style={{ 
                        background: event.type === 'Cardio' ? 'var(--accent)' : 
                               event.type === 'HIIT' ? 'var(--danger)' : 'var(--primary)' 
                      }}
                    >
                      <div style={{ fontWeight: 600, marginBottom: '4px' }}>{event.title}</div>
                      <div style={{ fontSize: '0.75rem', opacity: 0.9 }}>{event.time} • {event.duration}min</div>
                    </div>
                  ))
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Today's Schedule Details */}
      <div className="recent-card" style={{ marginTop: '24px' }}>
        <div className="table-header">
          <h3>Today's Workouts ({days[currentDay]})</h3>
        </div>
        {todaySchedule.length === 0 ? (
          <p style={{ color: 'var(--text-muted)', padding: '20px 0' }}>
            No workouts scheduled for today. Enjoy your rest day! 🧘
          </p>
        ) : (
          <table className="workout-table">
            <thead>
              <tr>
                <th>Time</th>
                <th>Workout</th>
                <th>Type</th>
                <th>Duration</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {todaySchedule.map((workout, index) => (
                <tr key={index}>
                  <td>{workout.time}</td>
                  <td>{workout.title}</td>
                  <td>
                    <span className={`type-badge ${workout.type.toLowerCase()}`}>
                      {workout.type}
                    </span>
                  </td>
                  <td>{workout.duration} min</td>
                  <td>
                    <button className="btn-secondary btn-small">Start</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default Schedule;
